def predict(triples: list[Triple]) -> str:
    """Generate a fluent, single complex sentence that combines information from all provided triples."""
    if not triples:
        return ""

    # Predicates where the subject is NOT the astronaut (keep full phrase)
    SUBJECT_AS_OBJECT = {"operator", "backupPilot", "commander", "crewMembers", "representative"}

    # Helper to strip surrounding quotes from objects
    def clean_obj(o: str) -> str:
        return o.strip('\"')

    # Phrase without repeating the subject (used when subject is the main entity)
    def phrase_no_subj(p: str, o: str) -> str:
        if p == "almaMater":
            return f"attended {o}"
        if p == "birthDate":
            return f"was born on {o}"
        if p == "birthName":
            return f"birth name is {o}"
        if p == "birthPlace":
            return f"was born in {o}"
        if p == "dateOfRetirement":
            return f"retired on {o}"
        if p == "occupation":
            return f"worked as a {o}"
        if p == "status":
            return f"is {o.lower()}"
        if p == "timeInSpace":
            return f"spent {o} minutes in space"
        if p == "mission":
            return f"flew on the {o} mission"
        if p == "selectedByNasa":
            return f"was selected by NASA in {o}"
        if p == "deathDate":
            return f"died on {o}"
        if p == "nationality":
            return f"was a {o} national"
        if p == "servedAsChiefOfTheAstronautOfficeIn":
            return f"served as chief of the Astronaut Office in {o}"
        if p == "title":
            return f"title is {o}"
        if p == "ribbonAward":
            return f"received the {o} ribbon award"
        if p == "alternativeName":
            return f"is also known as {o}"
        if p == "awards":
            return f"received {o} awards"
        # fallback
        return f"{p} {o}"

    # Full phrase for predicates where subject acts as object
    def full_phrase(s: str, p: str, o: str) -> str:
        if p == "operator":
            return f"{s} was operated by {o}"
        if p == "backupPilot":
            return f"The backup pilot of {s} was {o}"
        if p == "commander":
            return f"The commander of {s} was {o}"
        if p == "crewMembers":
            return f"The crew members of {s} include {o}"
        if p == "representative":
            return f"The representative of {s} is {o}"
        # generic fallback
        return f"{s} {p} {o}"

    # Group triples by subject
    from collections import defaultdict
    grouped = defaultdict(list)
    for t in triples:
        grouped[t.subject].append(t)

    subject_clauses = []
    for subj, tlist in grouped.items():
        # Build list of sub‑phrases for this subject
        sub_phrases = []
        for tr in tlist:
            p = tr.predicate
            o = clean_obj(tr.object)
            if p in SUBJECT_AS_OBJECT:
                # Use full phrase, no subject aggregation
                sub_phrases.append(full_phrase(tr.subject, p, o))
            else:
                sub_phrases.append(phrase_no_subj(p, o))

        # Combine sub‑phrases
        if len(sub_phrases) == 1:
            clause = f"{subj} {sub_phrases[0]}"
        else:
            # commas between all but last, and 'and' before last
            inner = ", ".join(sub_phrases[:-1]) + ", and " + sub_phrases[-1]
            clause = f"{subj} {inner}"
        subject_clauses.append(clause)

    # Combine all subject clauses into one sentence
    if len(subject_clauses) == 1:
        sentence = subject_clauses[0] + "."
    else:
        sentence = "; ".join(subject_clauses[:-1]) + "; and " + subject_clauses[-1] + "."
    return sentence

# EVOLVE-BLOCK-END

